class Solution:
    def lastInteger(self, n: int) -> int:
        arr = list(range(1, n + 1))
        turn = 1
        while len(arr) > 1:
            if turn == 1:
                arr = arr[0::2]
            else:
                rev = arr[::-1]
                kept_rev = rev[0::2]
                arr = kept_rev[::-1]
            turn = 2 if turn == 1 else 1
        return arr[0]

solutions.python:
class Solution:
    def lastInteger(self, n: int) -> int:
        head = 1
        step = 1
        count = n
        turn = 1
        while count > 1:
            if turn == 1:
                count = (count + 1) // 2
            else:
                if count % 2 == 0:
                    head = head + step
                    count = count // 2
                else:
                    count = (count + 1) // 2
            step *= 2
            turn = 2 if turn == 1 else 1
        return head

