var lastInteger = function(n) {
    let head = 1;
    let step = 1;
    let count = n;
    let turn = 1;
    while (count > 1) {
        if (turn === 1) {
            count = Math.floor((count + 1) / 2);
        } else {
            if (count % 2 === 0) {
                head = head + step;
                count = Math.floor(count / 2);
            } else {
                count = Math.floor((count + 1) / 2);
            }
        }
        step *= 2;
        turn = turn === 1 ? 2 : 1;
    }
    return head;
};
